INSERT INTO `products` VALUES (1,1,7,'수제 캐릭터 비즈 팔찌','작은 비즈를 하나씩 엮어 만든 캐릭터 감성의 수제 팔찌입니다.',15000,12000,30,3000,'APPROVED','ring_large.jpg','2026-05-28 00:22:45','2026-06-18 07:48:21',50000,'2026-05-28 09:22:45',NULL,NULL),(2,1,13,'라벤더 소이캔들','은은한 라벤더 향이 퍼지는 핸드메이드 소이캔들입니다.',22000,18000,20,3000,'APPROVED','costume_white.jpg','2026-05-28 00:22:45','2026-06-18 07:49:09',50000,'2026-05-28 09:22:45',NULL,NULL),(3,1,12,'캐릭터 컵받침 세트','귀여운 캐릭터 디자인이 들어간 수제 컵받침 세트입니다.',22000,18000,24,3000,'APPROVED','coaster_large.jpg','2026-05-28 06:49:19','2026-06-18 07:49:09',50000,'2026-05-28 16:55:53',NULL,NULL),(4,1,26,'수제 캐릭터 키링','가방이나 열쇠에 달기 좋은 귀여운 캐릭터 수제 키링입니다.',18000,15000,40,3000,'APPROVED','keyring_large.jpg','2026-06-02 08:06:05','2026-06-18 07:49:09',50000,'2026-06-02 17:06:05',NULL,NULL),(5,1,7,'캐릭터 반지 세트','캐릭터 포인트가 들어간 귀여운 수제 반지 세트입니다.',17000,13500,31,3000,'APPROVED','ring_large.jpg','2026-06-02 08:06:05','2026-06-19 03:25:55',50000,'2026-06-02 17:06:05',NULL,NULL),(6,1,10,'핸드메이드 코스튬 자켓','캐릭터 콘셉트로 제작된 핸드메이드 코스튬 자켓입니다.',39000,32000,14,3000,'APPROVED','costume_blue.jpg','2026-06-02 08:06:05','2026-06-19 03:25:55',70000,'2026-06-02 17:06:05',NULL,NULL),(7,1,27,'도담이','귀여운 도담이를 키워보세요',123456,123123,122,0,'APPROVED','1780990217612_KakaoTalk_20260605_170638192.jpg','2026-06-09 07:30:17','2026-06-19 01:33:16',0,'2026-06-09 16:30:17',NULL,NULL),(8,1,18,'123','123',123123123,123456,117,123,'APPROVED','1780990279614_KakaoTalk_20260605_170953599.jpg','2026-06-09 07:31:19','2026-06-19 01:28:39',0,'2026-06-09 16:31:19',NULL,NULL),(9,1,1,'이쁘져?','머롐ㄴㅇㅎㄴㅇ호농러ㅗ',35000,33000,4,0,'HIDDEN','1781064771236_스크린샷 2026-04-08 154732.png','2026-06-10 04:12:51','2026-06-18 07:49:09',0,'2026-06-10 13:12:51',NULL,NULL),(10,1,16,'부탁요','사진아 들어가라',160000,0,2,2500,'APPROVED','1781155367643_1779948967629_스크린샷 2026-02-25 122750.png','2026-06-11 05:22:47','2026-06-19 05:08:14',1000000,NULL,NULL,NULL),(11,1,25,'에디터','<h1><strong>글도 써지는 에디터</strong></h1><p><em>기울임</em></p><p><strong>볼드</strong></p><p><del>선긋기</del></p><di